patch:
--- a/decoder.v
+++ b/decoder.v
@@ -1,7 +1,7 @@
 module decoder_3to8(
     input [2:0] address,
     input enable,
-    output reg [7:0] outputs
+    output reg [7:0] decoded_out
 );
     always @(*)
         if (enable)
@@ -11,10 +11,10 @@
         else
-            outputs = 8'b0;
+            decoded_out = 8'b0;

 module top();
     wire [2:0] addr;
     wire en;
     wire [7:0] out_bus;
     decoder_3to8 inst(
         .address(addr),
         .enable(en),
-        .outputs(out_bus)
+        .decoded_out(out_bus)
     );

before_code:
module decoder_3to8(
    input [2:0] address,
    input enable,
    output reg [7:0] outputs
);
    always @(*)
        if (enable)
            outputs = 8'b1 << address;
        else
            outputs = 8'b0;
endmodule

module top();
    wire [2:0] addr;
    wire en;
    wire [7:0] out_bus;
    decoder_3to8 inst(
        .address(addr),
        .enable(en),
        .decoded_out(out_bus)
    );
endmodule

after_code:
module decoder_3to8(
    input [2:0] address,
    input enable,
    output reg [7:0] decoded_out
);
    always @(*)
        if (enable)
            decoded_out = 8'b1 << address;
        else
            decoded_out = 8'b0;
endmodule

module top();
    wire [2:0] addr;
    wire en;
    wire [7:0] out_bus;
    decoder_3to8 inst(
        .address(addr),
        .enable(en),
        .decoded_out(out_bus)
    );
endmodule
